INSERT INTO "brands" ("id","name","slug","color_primary","color_secondary","color_accent","color_background","voice_description","banned_terms","trademark_rules","character_style_rules","imagen_prefix","negative_prompt","brand_fonts") VALUES (gen_random_uuid(), 'Crown U', 'crown-u', '#E8B923', '#F4F1EA', '#C8911A', '#1E1E24', 'Social voice for Crown U · premium collegiate esports. Competitive, electric, and fan-first: broadcaster hype, not corporate. Punchy play-by-play energy that celebrates the moment. Use gaming terms naturally; never cringe slang.', ARRAY['disruption','synergy','game-changer','buckle up','get ready to'], 'Always capitalize the "U" in Crown U; never abbreviate to CU; use the full name in captions. The crown mark is locked · never redraw, recolor, or distort it. Gold is a premium accent, never a flat fill. No implied endorsement by real universities.', 'Stylized collegiate student-athletes in the Crown U character style; confident hero poses, consistent proportions, clean cel-style rendering; the crown motif as a premium mark, not a costume.', 'Premium collegiate-esports key art for Crown U. Heroic, prestige, championship energy. Rich gold as a premium accent on deep steel; high contrast, dramatic rim lighting, clean bold composition, athletic hero poses.', 'no clutter, no muddy or washed-out colors, no generic corporate stock look, no text, no watermarks, no non-Crown-U logos.', '[{"name":"Barlow Condensed","role":"display","weight":"600"},{"name":"Inter","role":"body","weight":"400"}]'::json) ON CONFLICT ("slug") DO UPDATE SET "name"=EXCLUDED.name, "color_primary"=EXCLUDED.color_primary, "color_secondary"=EXCLUDED.color_secondary, "color_accent"=EXCLUDED.color_accent, "color_background"=EXCLUDED.color_background, "voice_description"=EXCLUDED.voice_description, "banned_terms"=EXCLUDED.banned_terms, "trademark_rules"=EXCLUDED.trademark_rules, "character_style_rules"=EXCLUDED.character_style_rules, "imagen_prefix"=EXCLUDED.imagen_prefix, "negative_prompt"=EXCLUDED.negative_prompt, "brand_fonts"=EXCLUDED.brand_fonts, "updated_at"=now();
INSERT INTO "brands" ("id","name","slug","color_primary","color_secondary","color_accent","color_background","voice_description","banned_terms","trademark_rules","character_style_rules","imagen_prefix","negative_prompt","brand_fonts") VALUES (gen_random_uuid(), 'Rumble U', 'rumble-u', '#2E9BD6', '#16243F', '#F5A623', '#0E1726', 'Social voice for Rumble U · fierce, bold, and unapologetically competitive. Fighting spirit and underdog energy; powerful action verbs and short punchy lines. Signature tagline: Ready to Rumble.', ARRAY['disruption','synergy','game-changer','buckle up','get ready to'], 'Always capitalize the "U" in Rumble U; the tagline "Ready to Rumble" is always capitalized. The logo lockup is locked · never recolor or distort it.', 'Bold metallic-emblem brawler aesthetic · chrome steel-blue with orange-gold highlights over deep navy; high-energy clash and impact compositions.', 'High-impact esports key art for Rumble U. Metallic steel-blue with orange-gold accents on dark navy; chrome highlights, dramatic clash/impact energy, bold dynamic composition.', 'no clutter, no muddy or washed-out colors, no generic corporate stock look, no text, no watermarks, no non-Rumble-U logos.', '[{"name":"Barlow Condensed","role":"display","weight":"600"},{"name":"Inter","role":"body","weight":"400"}]'::json) ON CONFLICT ("slug") DO UPDATE SET "name"=EXCLUDED.name, "color_primary"=EXCLUDED.color_primary, "color_secondary"=EXCLUDED.color_secondary, "color_accent"=EXCLUDED.color_accent, "color_background"=EXCLUDED.color_background, "voice_description"=EXCLUDED.voice_description, "banned_terms"=EXCLUDED.banned_terms, "trademark_rules"=EXCLUDED.trademark_rules, "character_style_rules"=EXCLUDED.character_style_rules, "imagen_prefix"=EXCLUDED.imagen_prefix, "negative_prompt"=EXCLUDED.negative_prompt, "brand_fonts"=EXCLUDED.brand_fonts, "updated_at"=now();
INSERT INTO "brands" ("id","name","slug","color_primary","color_secondary","color_accent","color_background","voice_description","banned_terms","trademark_rules","character_style_rules","imagen_prefix","negative_prompt","brand_fonts") VALUES (gen_random_uuid(), 'Mascot Mayhem', 'mascot-mayhem', '#F2911B', '#7FB539', '#FFC23C', '#1B2A4A', 'Social voice for Mascot Mayhem · fun, chaotic, and entertaining. Lean into humor and mascot personality; playful and irreverent, never offensive. Emoji-forward and meme-aware.', ARRAY['disruption','synergy','game-changer','buckle up','get ready to'], 'Capitalize both words in Mascot Mayhem; "MM" is allowed in hashtags only. The logo lockup is locked.', 'Bright, chunky, playful mascot style · bold orange and lime green with thick dark outlines; exaggerated fun proportions and energetic, chaotic compositions.', 'Playful, high-energy mascot key art for Mascot Mayhem. Vibrant orange and lime green with thick dark outlines; fun and characterful, bold cartoon energy, dynamic poses.', 'no photorealism, no muted or dark-only palettes, no corporate look, no text, no watermarks, no non-Mascot-Mayhem logos.', '[{"name":"Barlow Condensed","role":"display","weight":"600"},{"name":"Inter","role":"body","weight":"400"}]'::json) ON CONFLICT ("slug") DO UPDATE SET "name"=EXCLUDED.name, "color_primary"=EXCLUDED.color_primary, "color_secondary"=EXCLUDED.color_secondary, "color_accent"=EXCLUDED.color_accent, "color_background"=EXCLUDED.color_background, "voice_description"=EXCLUDED.voice_description, "banned_terms"=EXCLUDED.banned_terms, "trademark_rules"=EXCLUDED.trademark_rules, "character_style_rules"=EXCLUDED.character_style_rules, "imagen_prefix"=EXCLUDED.imagen_prefix, "negative_prompt"=EXCLUDED.negative_prompt, "brand_fonts"=EXCLUDED.brand_fonts, "updated_at"=now();
INSERT INTO "brands" ("id","name","slug","color_primary","color_secondary","color_accent","color_background","voice_description","banned_terms","trademark_rules","character_style_rules","imagen_prefix","negative_prompt","brand_fonts") VALUES (gen_random_uuid(), 'Sparq', 'corporate', '#00A19C', '#1E1E24', '#EB0028', '#0D0D14', 'Social voice for Sparq Games. Bold, forward-thinking, and credible · gritty underdog confidence without jargon. Break free, play future. Focus on milestones, partnerships, and industry leadership; inspiring, not stiff.', ARRAY['disruption','synergy','game-changer','buckle up','get ready to'], 'Always "Sparq Games" with proper capitalization; never "SG". Grit Teal #00A19C and the Sparq mark are locked brand identity.', 'Sparq house style · gritty, premium, and tech-forward; Grit Teal and steel with selective Outlaw Red accents; bold athletic-tech energy.', 'Sparq Games brand key art. Gritty, premium, tech-forward; Grit Teal (#00A19C) and steel with selective Outlaw Red (#EB0028) accents; bold high-contrast composition.', 'no clutter, no muddy or washed-out colors, no generic corporate stock look, no text, no watermarks.', '[{"name":"Barlow Condensed","role":"display","weight":"600"},{"name":"Oxanium","role":"hud","weight":"600"},{"name":"Inter","role":"body","weight":"400"}]'::json) ON CONFLICT ("slug") DO UPDATE SET "name"=EXCLUDED.name, "color_primary"=EXCLUDED.color_primary, "color_secondary"=EXCLUDED.color_secondary, "color_accent"=EXCLUDED.color_accent, "color_background"=EXCLUDED.color_background, "voice_description"=EXCLUDED.voice_description, "banned_terms"=EXCLUDED.banned_terms, "trademark_rules"=EXCLUDED.trademark_rules, "character_style_rules"=EXCLUDED.character_style_rules, "imagen_prefix"=EXCLUDED.imagen_prefix, "negative_prompt"=EXCLUDED.negative_prompt, "brand_fonts"=EXCLUDED.brand_fonts, "updated_at"=now();